function checkMyStyle() {
            var val = document.getElementById("investmentPriority").value;
            var resultBox = document.getElementById("styleResultBox");
            var resultText = document.getElementById("styleResultText");

            if(val === "robo") {
                resultText.innerHTML = "🤖 알고리즘 매칭형! 감정에 흔들리지 않는 합리적인 '로보어드바이저' 글로벌 자산 배분이 더 적합합니다.";
            } else {
                resultText.innerHTML = "👩‍💼 휴먼 PB 밀착형! 자산 규모가 크고 상속/증여 등 복잡한 정성적 상담이 필요한 '인간 전문가 케어'가 적합합니다.";
            }
            resultBox.style.display = "block";
        }

