.single-summary-card-container {
            font-family: 'Noto Sans KR', sans-serif;
            display: flex;
            justify-content: center;
            align-items: center;
            padding: 20px 10px;
            background-color: #f7fafc;
            margin: 20px 0;
        }
        .single-summary-card {
            width: 100%;
            max-width: 700px;
            background-color: #ffffff;
            border-radius: 12px;
            box-shadow: 0 6px 18px rgba(0,0,0,0.08);
            padding: 25px;
            display: flex;
            flex-direction: column;
            overflow: hidden;
            border: 1px solid #cbd5e0;
        }
        .single-summary-card .card-header {
            display: flex;
            align-items: center;
            border-bottom: 2px solid #2b6cb0;
            padding-bottom: 12px;
            margin-bottom: 12px;
        }
        .single-summary-card .card-header-icon {
            font-size: 34px;
            color: #2b6cb0;
            margin-right: 14px;
        }
        .single-summary-card .card-header h3 {
            font-size: 24px;
            color: #2b6cb0;
            margin: 0;
            line-height: 1.3;
            font-weight: 700;
        }
        .single-summary-card .card-content {
            flex-grow: 1;
            display: flex;
            flex-direction: column;
            justify-content: space-around;
            font-size: 16px;
            line-height: 1.6;
            color: #4a5568;
        }
        .single-summary-card .card-content .section {
            margin-bottom: 10px;
        }
        .single-summary-card .card-content strong {
            color: #2b6cb0;
            font-weight: 600;
        }
        .single-summary-card .card-content .highlight {
            background-color: #edf2f7;
            padding: 2px 6px;
            border-radius: 3px;
            font-weight: bold;
            color: #2b6cb0;
        }
        .single-summary-card .card-content .formula {
            background-color: #ebf8ff;
            padding: 8px 12px;
            border-radius: 4px;
            font-size: 0.95em;
            text-align: center;
            margin-top: 5px;
            color: #2c5282;
            font-weight: bold;
        }
        .single-summary-card .card-footer {
            font-size: 13px;
            color: #718096;
            text-align: center;
            padding-top: 12px;
            border-top: 1px dashed #cbd5e0;
            margin-top: auto;
